namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = [];
    private readonly Lock _lock = new();
    private static readonly string[] SampleMessages =
    [
        "Deployment to production completed successfully.",
        "New user registered: alice@example.com",
        "CPU usage exceeded 90% on server-03.",
        "Backup finished for database 'orders'.",
        "Pull request #42 was merged.",
        "SSL certificate expires in 7 days.",
        "New comment on issue #108.",
        "Scheduled maintenance window starts at 02:00 UTC.",
        "Payment processed: $149.99",
        "Service 'inventory-api' restarted automatically.",
    ];

    public NotificationService()
    {
        // Seed a few initial notifications
        var now = DateTime.UtcNow;
        for (var i = 0; i < 3; i++)
        {
            _notifications.Add(new Notification(_nextId++, SampleMessages[i], now.AddMinutes(-10 + i)));
        }
    }

    /// <summary>Returns all notifications known so far.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateNewNotification()
    {
        lock (_lock)
        {
            var msg = SampleMessages[_nextId % SampleMessages.Length];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

