@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService Svc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>#@n.Id</strong> &mdash; @n.Message
                </div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification> notifications { get; set; } = [];

    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // ??= ensures we skip the fetch when state was restored from prerender
        if (notifications.Count == 0)
        {
            notifications = Svc.GetAll();
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs in the interactive render — never during prerender
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate a new notification arriving on each poll
            Svc.SimulateNewNotification();

            var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var fresh = Svc.GetSince(lastId);

            if (fresh.Count > 0)
            {
                await InvokeAsync(() =>
                {
                    notifications.AddRange(fresh);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

